month']==1) {$month=12; $year=$_POST['year']-1; $year="0".$year;} else {$month = $_POST['month']-1; $year=$_POST['year'];} calendar($_POST['day'],$month,$year,0); break; case ">": //up if ($_POST['month']==12) {$month=1; $year=$_POST['year']+1;$year="0".$year;} else {$month = $_POST['month']+1; $year=$_POST['year'];} calendar($_POST['day'],$month,$year,0); break; case "Vandaag": calendar(date("d"),date("m"),date("y"),0); break; case "Toon": calendar(substr($_POST['date'],0,2),substr($_POST['date'],3,2), substr($_POST['date'],6,2),0); break; case "edit": edit_date(substr($_POST['date'],6,2)."-".substr($_POST['date'],3,2). "-".substr($_POST['date'],0,2),$_POST['body']); calendar(substr($_POST['date'],0,2),substr($_POST['date'],3,2), substr($_POST['date'],6,2),0); break; default: calendar(date("d"),date("m"),date("y"),0); break; } ?> jan schreef op 02.09.2005 10:49 fijne kalender, waarvoor dank! Ik probeer de zaak zo aan te passen, dat een gebruiker elke dag de keuze heeft uit drie radiobuttons (vrij, bellen, bezet). Na 'edit' verschijnt de betreffende dag in groen, oranje of rood. De doorgevoerde aanpassing (kleurverandering e.d.) werken reeds goed in onderstaand script, behalve het wegschrijven van de waarde van de radio button naar de database... Kan iemand mij helpen? <!DOCTYPE HTML PUBLIC "-//W3C//DTD HTML 4.01 Transitional//EN"> <html> <!-- ik heb wat opmaak dingetjes laten vallen... niet nodig en het wordt zo bont --> <head> <style type="text/css"> input {border : 1px #000000 solid;} th {background-color: #eeeeee;} .line {border: 3px #000000 solid;} .vandaaggroen{font-weight:bolt ;background-color: #33CC00; border: 3px #000000 solid;} .vandaagoranje {font-weight:bolt ;background-color: #FF6633;border: 3px #000000 solid;} .vandaagrood {font-weight:bolt ;background-color: #FF0000;border: 3px #000000 solid;} .vandaagcrash {font-weight:bolt ;background-color: #FFFFFF;border: 3px #000000 solid;} .dik {font-weight:bolt