binding: connect2db(); $query = "select body from bbhc_calendar where date=\"$date\""; $result = mysql_query($query) or die ("Query failed"); $body = mysql_fetch_array($result); if ($body[0]==null) return "no entry"; else return $body[0]; } function connect2db(){ $user="cappellej"; $pass="ffCkOBAI"; $db="cappellej"; $host="mysqlhost"; // ---------- // pre: - // post: maakt verbinding met de database if (!@mysql_select_db("$db", @mysql_connect("$host", "$user", "$pass"))) { echo "Er kon geen connectie worden gemaakt met de database."; exit(); } } ////////////////// // main ////////////////// // formulier afvangen // datums afvangen if (isset($_POST['this_date'])){ calendar(substr($_POST['this_date'],0,2),substr($_POST['date'],3,2), substr($_POST['date'],6,2),1); } else switch ($_POST['button']){ case "<": //down if ($_POST['month']==1) {$month=12; $year=$_POST['year']-1; $year="0".$year;} else {$month = $_POST['month']-1; $year=$_POST['year'];} calendar($_POST['day'],$month,$year,0); break; case ">": //up if ($_POST['month']==12) {$month=1; $year=$_POST['year']+1;$year="0".$year;} else {$month = $_POST['month']+1; $year=$_POST['year'];} calendar($_POST['day'],$month,$year,0); break; case "Vandaag": calendar(date("d"),date("m"),date("y"),0); break; case "Toon": calendar(substr($_POST['date'],0,2),substr($_POST['date'],3,2), substr($_POST['date'],6,2),0); break; case "edit": edit_date(substr($_POST['date'],6,2)."-".substr($_POST['date'],3,2). "-".substr($_POST['date'],0,2),$_POST['body']); calendar(substr($_POST['date'],0,2),substr($_POST['date'],3,2), substr($_POST['date'],6,2),0); break; default: calendar(date("d"),date("m"),date("y"),0); break; } ?> Tessa schreef op 29.01.2006 17:09 BTW, leuk script, maar is het iemand opgevallen dat ie niet W3C valid is?!?, zit de fout zit in de afsluiting v/d loop, heb vanalles geprobeerd maar kom er nie uit. (ben ook maar een beginneling in PHP. if (($endd